t.script:
                function loadBuildings() {
                    const communityId = document.querySelector('[name="community_id"]').value;
                    const buildingSelect = document.getElementById('building_id');
                    const floorSelect = document.getElementById('floor_id');
                    const flatSelect = document.getElementById('flat_id');

                    buildingSelect.innerHTML = 'Loading...';
                    floorSelect.innerHTML = 'Select floor (optional)';
                    flatSelect.innerHTML = 'Select flat';

                    if (!communityId) {
                        buildingSelect.innerHTML = 'First select community';
                        return;
                    }

                    fetch('/resident/get_buildings', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ params: { community_id: parseInt(communityId) } })
                    })
                    .then(response => response.json())
                    .then(data => {
                        buildingSelect.innerHTML = 'Select building';
                        data.result.forEach(b => {
                            const opt = document.createElement('option');
                            opt.value = b.id;
                            opt.text = b.name;
                            buildingSelect.appendChild(opt);
                        });
                    })
                    .catch(err => {
                        console.error('Error loading buildings:', err);
                        buildingSelect.innerHTML = 'Error loading';
                    });
                }

                function loadFloorsAndFlats() {
                    const buildingId = document.getElementById('building_id').value;
                    const floorSelect = document.getElementById('floor_id');
                    const flatSelect = document.getElementById('flat_id');

                    floorSelect.innerHTML = 'Loading...';
                    flatSelect.innerHTML = 'Loading...';

                    if (!buildingId) return;

                    Promise.all([
                        fetch('/resident/get_floors', {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({ params: { building_id: parseInt(buildingId) } })
                        }).then(r => r.json()),
                        fetch('/resident/get_flats', {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({ params: { building_id: parseInt(buildingId) } })
                        }).then(r => r.json())
                    ])
                    .then(([floorsData, flatsData]) => {
                        floorSelect.innerHTML = 'Select floor (optional)';
                        floorsData.result.forEach(f => {
                            const opt = document.createElement('option');
                            opt.value = f.id;
                            opt.text = f.name;
                            floorSelect.appendChild(opt);
                        });

                        flatSelect.innerHTML = 'Select flat';
                        flatsData.result.forEach(fl => {
                            const opt = document.createElement('option');
                            opt.value = fl.id;
                            opt.text = fl.name;
                            flatSelect.appendChild(opt);
                        });
                    })
                    .catch(err => {
                        console.error('Error loading floors/flats:', err);
                        floorSelect.innerHTML = 'Error';
                        flatSelect.innerHTML = 'Error';
                    });
                }
